start.evaluate:
/**
 * Pure JavaScript Function that Evaluate if condition should trigger and
 * optionally enriches the update payload of the processed document
 * 
 * @param $document - The document that is being processed
 * @param $window - The Event window object eg. {start:"XXX", end:"YYY"}
 * 
 * @returns A single boolean (true if event should trigger) or [boolean, object]
 * where boolean must be true if event should trigger and the optional object is 
 * the additional document update payload when the event is triggered
 */

const content_channels = new Set($document.content_channels ?? []);
if($window.channel) content_channels.add($window.channel);

const content_rights = new Set($document.content_rights ?? []);
if($window.right) content_rights.add($window.right);

const content_channels_rights = new Set($document.content_channels_rights ?? []);
if($window.right && $window.channel) content_channels_rights.add(`${$window.channel}_${$window.right}`)

return [true, {
        content_channels: [...content_channels], 
        content_rights: [...content_rights], 
        content_channels_rights: [...content_channels_rights]
        }];

end.evaluate:
/**
 * Pure JavaScript Function that Evaluate if condition should trigger and
 * optionally enriches the update payload of the processed document
 * 
 * @param $document - The document that is being processed
 * @param $window - The Event window object eg. {start:"XXX", end:"YYY"}
 * 
 * @returns A single boolean (true if event should trigger) or [boolean, object]
 * where boolean must be true if event should trigger and the optional object is 
 * the additional document update payload when the event is triggered
 */

const content_channels = new Set($document.content_channels ?? []);
content_channels.delete($window.channel);

const content_rights = new Set($document.content_rights ?? []);
content_rights.delete($window.right);

const content_channels_rights = new Set($document.content_channels_rights ?? []);
content_channels_rights.delete(`${$window.channel}_${$window.right}`)

return [true, {
        content_channels: [...content_channels], 
        content_rights: [...content_rights], 
        content_channels_rights: [...content_channels_rights]
        }];

